// palette.ts emitter — the generated TypeScript view of the token source.
// Emitted at the exact path with the exact exports the hand-written module
// had (Palette, dark, light), so .storybook/theme.ts and every TS consumer
// keeps working; adds TokenName/ThemeName unions and a palettes record.

const IDENT_RE = /^[a-z][a-zA-Z0-9_]*$/;

const keyLiteral = (key) => (IDENT_RE.test(key) ? key : `'${key}'`);

const paletteLiteral = (theme) => {
  // The typed internal doubles as a completeness check: the literal must
  // carry every TokenName key or the generated file fails to typecheck.
  const lines = [`const ${theme.name}Tokens: Record<TokenName, string> = {`];
  theme.colors.forEach((row, index) => {
    const comma = index === theme.colors.length - 1 ? '' : ',';
    const comment = row.description ? ` // ${row.description}` : '';
    lines.push(`  ${keyLiteral(row.key)}: '${row.css}'${comma}${comment}`);
  });
  lines.push('};', '', `export const ${theme.name}: Palette = ${theme.name}Tokens;`);
  return lines;
};

export const emitPaletteTs = (themes) => {
  const named = themes.filter((t) => IDENT_RE.test(t.name));
  if (named.length !== themes.length) {
    // Non-identifier theme names would need a different export strategy;
    // fail loudly rather than silently dropping a theme.
    const bad = themes.filter((t) => !IDENT_RE.test(t.name)).map((t) => t.name);
    throw new Error(`emitPaletteTs: theme names must be valid TS identifiers: ${bad.join(', ')}`);
  }
  const first = themes[0];
  const tokenNames = first.colors.map((row) => `  | '${row.key}'`);
  const themeNames = themes.map((t) => `'${t.name}'`).join(' | ');

  const lines = [
    '// GENERATED by scripts/build-tokens.mjs — do not edit by hand.',
    '// Source of truth: the DTCG token files (*.tokens.json) + themes.ts.',
    '// Keys mirror the --sv-* CSS custom properties (without the prefix).',
    '',
    'export type Palette = Record<string, string>;',
    '',
    'export type TokenName =',
    ...tokenNames.slice(0, -1),
    `${tokenNames[tokenNames.length - 1]};`,
    '',
    `export type ThemeName = ${themeNames};`,
    ''
  ];
  for (const theme of themes) {
    lines.push(...paletteLiteral(theme), '');
  }
  lines.push(
    'export const palettes: Record<ThemeName, Readonly<Record<TokenName, string>>> = {',
    themes.map((t) => `  ${t.name}: ${t.name}Tokens`).join(',\n'),
    '};',
    ''
  );
  return lines.join('\n');
};
